// // This module implements a down-up counter with a 3-bit output and a carry-out signal. It decrements when the up_down input is high and increments when it is low. Upon reaching the minimum value of 0 (000 in binary), it wraps around to 7 and sets the carry_out signal to high. Conversely, when incrementing, if it reaches 7 (111 in binary), it wraps around to 0 and also sets carry_out high. A reset input initializes the counter to 7 and clears the carry_out signal.
module top_module(
  input clk,
  input reset,
  input up_down,
  output reg [2:0] q,
  output reg carry_out
);always @(posedge clk) begin
    if(reset) begin
      q <= 3'b0;
      carry_out <= 1'b0;
    end
    else if(up_down) begin
      if(q == 3'b111) begin
        q <= 3'b000;
        carry_out <= 1'b1;
      end
      else begin
        q <= q + 1;
        carry_out <= 1'b0;
      end
    end
    else begin
      if(q == 3'b000) begin
        q <= 3'b111;
        carry_out <= 1'b1;
      end
      else begin
        q <= q - 1;
        carry_out <= 1'b0;
      end
    end
  end

endmodule
